import java.util.*;
public class RecordMutableBug {
    record Tag(String name, List<String> values) {}
    public static void main(String[] args) {
        List<String> vals = new ArrayList<>(List.of("a", "b"));
        Tag t = new Tag("x", vals);
        vals.add("c");  // bug: mutates the record's internal list
        System.out.println(t.values().size());
    }
